Define a theme object:

```jsx
// theme.js
export const lightTheme = {
  colors: {
    primary: '#6200ee',
    background: '#ffffff',
    text: '#000000',
  },
  spacing: {
    small: 8,
    medium: 16,
    large: 24,
  },
};

export const darkTheme = {
  colors: {
    primary: '#bb86fc',
    background: '#121212',
    text: '#ffffff',
  },
  spacing: { ... },
};
```

Then use React Context to provide the theme to components.

## Consuming Theme

Create a `ThemeContext` and a `ThemeProvider`. Then in components:

```jsx
import { ThemeContext } from './ThemeContext';

function MyComponent() {
  const theme = useContext(ThemeContext);

  return (
    <View style={{ backgroundColor: theme.colors.background }}>
      <Text style={{ color: theme.colors.text }}>Hello</Text>
    </View>
  );
}
```

This allows dynamic theming (e.g., switching light/dark mode).

## CSS‑in‑JS Libraries

Libraries like `styled-components` or `emotion` allow you to write actual CSS syntax in your components:

```jsx
import styled from 'styled-components/native';

const Container = styled.View`
  flex: 1;
  background-color: ${props => props.theme.background};
`;

const Title = styled.Text`
  font-size: 24px;
  color: palevioletred;
`;

function App() {
  return (
    <Container>
      <Title>Hello</Title>
    </Container>
  );
}
```

This is a personal preference; StyleSheet works perfectly well.
